document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".js-blur-words").forEach(o=>{let n=o.textContent.trim().split(/\s+/);o.textContent="",n.forEach((e,t)=>{var r=document.createElement("span");r.className="blur-word",r.textContent=e,o.appendChild(r),t<n.length-1&&o.appendChild(document.createTextNode(" "))});var e=o.querySelectorAll(".blur-word");gsap.set(o,{visibility:"visible"}),gsap.fromTo(e,{filter:"blur(10px)",opacity:0,y:"0.15em"},{filter:"blur(0px)",opacity:1,y:"0em",duration:1.8,stagger:.08,ease:"power4.out"})})}),document.addEventListener("DOMContentLoaded",()=>{gsap.registerPlugin(ScrollTrigger),document.querySelectorAll(".blur-in").forEach(o=>{let n=o.textContent.trim().split(/\s+/);o.textContent="",n.forEach((e,t)=>{var r=document.createElement("span");r.className="blur-word",r.textContent=e,o.appendChild(r),t<n.length-1&&o.appendChild(document.createTextNode(" "))});var e=o.querySelectorAll(".blur-word");gsap.fromTo(e,{filter:"blur(10px)",opacity:0,y:"0.4em"},{filter:"blur(0px)",opacity:1,y:"0em",duration:2,stagger:.07,ease:"power4.out",scrollTrigger:{trigger:o,start:"top 85%",end:"top 40%",toggleActions:"play none none none",once:!0}})})});